settings.markdownTextFunction:
let env = "schnelliot";
let email = ctx.currentUser.sub;
let name = ctx.currentUser.firstName;
let userId = ctx.currentUser.userId;
let token = localStorage.getItem("jwt_token");
let cacheBuster = new Date().getTime();

window.tbWidgetContext = ctx;

let tbFilters = {};
try {
    if (ctx.aliasController) {
        let filters = ctx.aliasController.getFilters();
        for (let filterId in filters) {
            if (filters.hasOwnProperty(filterId)) {
                let f = filters[filterId];
                let val = "";
                if (f.keyValues && f.keyValues.length > 0) {
                    val = f.keyValues[0];
                } else if (f.valueList && f.valueList.length > 0) {
                    val = f.valueList[0];
                } else if (f.value !== undefined) {
                    val = f.value;
                }
                if (val !== undefined && val !== null) {
                    tbFilters[f.filter] = val;
                }
            }
        } 
    }
} catch (e) {
    console.error("Error reading dashboard filters:", e);
}

let filterParams = encodeURIComponent(JSON.stringify(tbFilters));

return `<div class='card'>\n<iframe \n  id="ticketsIframe"\n  width="100%" \n  height="100%" \n  src="https://schnelliot-380113.web.app/?env=${env}&token=${token}&userId=${userId}&userEmail=${email}&user=${name}&cb=${cacheBuster}&tbFilters=${filterParams}" \n  frameborder="0" \n  style="border:0"\n  allow="clipboard-read; clipboard-write">\n</iframe>\n<script>\n(function() {\n    let iframe = document.getElementById("ticketsIframe");\n    if (!iframe) return;\n    \n    function sendFilters() {\n        try {\n            let context = window.parentContext || window.tbWidgetContext;\n            if (context && context.aliasController) {\n                let filters = context.aliasController.getFilters();\n                let filterMap = {};\n                for (let filterId in filters) {
                    if (filters.hasOwnProperty(filterId)) {
                        let f = filters[filterId];\n                        let val = "";\n                        if (f.keyValues && f.keyValues.length > 0) {
                            val = f.keyValues[0];\n                        } else if (f.valueList && f.valueList.length > 0) {
                            val = f.valueList[0];\n                        } else if (f.value !== undefined) {
                            val = f.value;\n                        }\n                        if (val !== undefined && val !== null) {
                            filterMap[f.filter] = val;
                        }\n                    }\n                }\n                iframe.contentWindow.postMessage({\n                    type: "tbFilters",\n                    filters: filterMap\n                }, "*");\n            }\n        } catch (e) {}\n    }\n    \n    setInterval(sendFilters, 2000);\n})();\n<\/script>\n    </div>`;

